<?php
namespace App\Services\Security;
use App\Models\{SecurityGovernanceNotification,SecurityIncident,User};use Illuminate\Support\Str;
class SecurityIncidentService{public function openIncident(User $a,array $d):SecurityIncident{$i=SecurityIncident::create(['incident_number'=>'SEC-'.now()->format('Ymd').'-'.Str::upper(Str::random(6)),'status'=>'open','severity'=>$d['severity']??'medium','source_type'=>$d['source_type']??null,'source_id'=>$d['source_id']??null,'title'=>$d['title'],'description'=>$d['description']??null,'opened_by_id'=>$a->id,'opened_at'=>now(),'due_at'=>$d['due_at']??now()->addDay()]);$this->event($i,$a,'opened','Security incident opened.');return $i;}public function openFromNotification(SecurityGovernanceNotification $n,User $a,string $reason):SecurityIncident{$i=$this->openIncident($a,['severity'=>$n->severity,'source_type'=>SecurityGovernanceNotification::class,'source_id'=>$n->id,'title'=>$n->subject,'description'=>$reason]);$n->update(['incident_id'=>$i->id]);$n->events()->create(['actor_id'=>$a->id,'event_type'=>'incident_opened','description'=>$reason,'created_at'=>now()]);$this->event($i,$a,'source_linked','Governance notification linked.');return $i;}public function assign($i,User $a,User $assignee,string $reason){$i->update(['assigned_to_id'=>$assignee->id]);$this->event($i,$a,'assigned',$reason);return $i->refresh();}public function transition($i,User $a,string $status,string $note){$i->update(['status'=>$status,$status==='triaged'?'triaged_at':'updated_at'=>now()]);$this->event($i,$a,$status,$note);return $i->refresh();}public function resolve($i,User $a,string $summary){$i->update(['status'=>'resolved','resolved_by_id'=>$a->id,'resolved_at'=>now(),'resolution_summary'=>$summary]);$this->event($i,$a,'resolved',$summary);return $i->refresh();}public function cancel($i,User $a,string $reason){$i->update(['status'=>'cancelled']);$this->event($i,$a,'cancelled',$reason);return $i->refresh();}private function event($i,$a,$t,$d){$i->events()->create(['actor_id'=>$a->id,'event_type'=>$t,'description'=>$d,'created_at'=>now()]);}}
